public interface IProxyService
{
    Task<HttpResponseMessage> ProxyRequestAsync(string url, string method, string body = null);
}

public class ProxyService : IProxyService
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyService(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    public async Task<HttpResponseMessage> ProxyRequestAsync(string url, string method, string body = null)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var request = new HttpRequestMessage(new HttpMethod(method), url)
        {
            Content = body != null ? new StringContent(body) : null
        };

        return await httpClient.SendAsync(request);
    }
}
``

